class Solution:
    def splitWordsBySeparator(self, words, separator):
        res = []
        for w in words:
            piece = ''
            for ch in w:
                if ch == separator:
                    if piece:
                        res.append(piece)
                    piece = ''
                else:
                    piece += ch
            if piece:
                res.append(piece)
        return res

